const TabPrev = ({d,set}) => {
  const {pv,mp,sconto} = d;
  const calc = useMemo(()=>{
    const r = (on,v=0) => on?(Number(v)||0):0;
    let sub = 0;
    sub += r(pv.drinkCard.on,(pv.drinkCard.q||0)*P.drinkCard);
    sub += r(pv.waterExtra.on,(pv.waterExtra.q||0)*P.waterExtra);
    sub += r(pv.openBar.on,P.openBar);
    sub += r(pv.aperitivo.on,(pv.aperitivo.q||0)*P.aperitivo);
    sub += pv.torta.on?(Number(pv.torta.kg)||0)*P.torta:0;
    sub += r(pv.tortaArt.on,P.tortaArt);
    sub += r(pv.taglio.on,(pv.taglio.q||0)*P.taglio);
    sub += r(pv.mini.on,(pv.mini.q||0)*P.miniDessert);
    sub += r(pv.invito.on,P.invito);
    sub += r(pv.ledwall.on,P.ledwall);
    sub += r(pv.cadeaux.on,(pv.cadeaux.q||0)*P.cadeaux);
    sub += r(pv.sweetTable.on,P.sweetTable);
    sub += r(pv.confettata.on,(pv.confettata.q||0)*P.confettata);
    sub += r(pv.fullTable.on,(pv.fullTable.q||0)*P.fullTable);
    sub += r(pv.siaeDj.on,P.siaeDj);
    sub += r(pv.siae.on,P.siae);
    sub += r(pv.speaker.on,P.speaker);
    sub += r(pv.fotografo.on,P.fotografo);
    sub += r(pv.animazione.on,pv.animazione.e);
    sub += r(pv.strumento.on,pv.strumento.e);
    sub += r(pv.instax.on,P.instax);
    sub += r(pv.telo.on,P.telo);
    sub += r(pv.fuochi.on,P.fuochi);
    sub += r(pv.fontane.on,P.fontane);
    sub += r(pv.altalena.on,pv.altalena.e);
    sub += r(pv.cerchioG.on,pv.cerchioG.e);
    sub += r(pv.cerchioP.on,pv.cerchioP.e);
    const menuTot = ["smart","comfort","sharing","bimbi"].reduce((a,k)=>a+(Number(mp[k].pax)||0)*(Number(mp[k].ep)||0),0);
    const extra = Number(mp.extra)||0;
    const tot = sub+menuTot+extra;
    const sc = tot*(Number(sconto)||0)/100;
    return {sub,menuTot,extra,tot,sc,totSc:tot-sc};
  },[pv,mp,sconto]);

  const Row = ({label,price,on,setOn,qty,setQty,unit,extra,setExtra}) => (
    <div style={{display:"flex",alignItems:"center",gap:5,padding:"3px 0",borderBottom:`1px solid ${T.light}`}}>
      <input type="checkbox" checked={!!on} onChange={e=>setOn(e.target.checked)}
        style={{width:12,height:12,accentColor:T.teal,cursor:"pointer",flexShrink:0}} />
      <span style={{flex:1,fontSize:12,color:on?T.text:"#9DBCC1"}}>{label}</span>
      {price!=null && <span style={{fontSize:10.5,color:T.sub,minWidth:40,textAlign:"right"}}>{price}€</span>}
      {setQty && <I value={qty??""} onChange={setQty} w={45} type="number"
        sx={{textAlign:"center",padding:"2px 4px",fontSize:11}} />}
      {setExtra && <I value={extra??""} onChange={setExtra} placeholder="€" w={55} sx={{fontSize:11}} />}
      {unit && <span style={{fontSize:10,color:T.sub,whiteSpace:"nowrap"}}>{unit}</span>}
    </div>
  );

  return (
    <div>
      <div style={{display:"flex",gap:8,alignItems:"center",marginBottom:12,flexWrap:"wrap"}}>
        <span style={{fontSize:13,fontWeight:"700",color:T.teal}}>Preventivo su Invitati Presunti</span>
        <span style={{flex:1}}/>
        <span style={{fontSize:12,color:T.sub}}>Valido fino al:</span>
        <I value={d.prevFino} onChange={v=>set("prevFino",v)} type="date" w={155} />
      </div>
      <div style={{display:"grid",gridTemplateColumns:"3fr 2fr",gap:14}}>
        <div>
          <Box title="Drink e Aperitivo di Benvenuto" sx={{marginBottom:10}}>
            <Row label="Drink Card" price={P.drinkCard} on={pv.drinkCard.on} setOn={v=>set("pv.drinkCard.on",v)} qty={pv.drinkCard.q} setQty={v=>set("pv.drinkCard.q",v)} unit="×" />
            <Row label="Water Station Extra" price={`${P.waterExtra}/10bott`} on={pv.waterExtra.on} setOn={v=>set("pv.waterExtra.on",v)} qty={pv.waterExtra.q} setQty={v=>set("pv.waterExtra.q",v)} unit="×" />
            <Row label="Open Bar" price={`${P.openBar} d.e.`} on={pv.openBar.on} setOn={v=>set("pv.openBar.on",v)} />
            <Row label="Aperitivo di Benvenuto" price={P.aperitivo} on={pv.aperitivo.on} setOn={v=>set("pv.aperitivo.on",v)} qty={pv.aperitivo.q} setQty={v=>set("pv.aperitivo.q",v)} unit="pax" />
          </Box>
          <Box title="Torta e Dessert" sx={{marginBottom:10}}>
            <Row label="Torta" price="45/kg" on={pv.torta.on} setOn={v=>set("pv.torta.on",v)} qty={pv.torta.kg} setQty={v=>set("pv.torta.kg",v)} unit="kg" />
            <Row label="Bollicine con torta" on={pv.bollicine.on} setOn={v=>set("pv.bollicine.on",v)} qty={pv.bollicine.q} setQty={v=>set("pv.bollicine.q",v)} unit="bott." />
            <Row label="Torta Artificiale (solo x foto)" price={P.tortaArt} on={pv.tortaArt.on} setOn={v=>set("pv.tortaArt.on",v)} />
            <Row label="Diritto di Taglio" price="2/per." on={pv.taglio.on} setOn={v=>set("pv.taglio.on",v)} qty={pv.taglio.q} setQty={v=>set("pv.taglio.q",v)} unit="pax" />
            <Row label="Mini Dessert" price={P.miniDessert} on={pv.mini.on} setOn={v=>set("pv.mini.on",v)} qty={pv.mini.q} setQty={v=>set("pv.mini.q",v)} unit="pax" />
          </Box>
          <Box title="Allestimento" sx={{marginBottom:10}}>
            <Row label="Invito Digitale" price={P.invito} on={pv.invito.on} setOn={v=>set("pv.invito.on",v)} />
            <Row label="LedWall" price={P.ledwall} on={pv.ledwall.on} setOn={v=>set("pv.ledwall.on",v)} />
            <Row label="Un Dolce Cadeaux" price={P.cadeaux} on={pv.cadeaux.on} setOn={v=>set("pv.cadeaux.on",v)} qty={pv.cadeaux.q} setQty={v=>set("pv.cadeaux.q",v)} unit="pax" />
            <Row label="Sweet Table base" price={P.sweetTable} on={pv.sweetTable.on} setOn={v=>set("pv.sweetTable.on",v)} />
            <Row label="Confettata" price={P.confettata} on={pv.confettata.on} setOn={v=>set("pv.confettata.on",v)} qty={pv.confettata.q} setQty={v=>set("pv.confettata.q",v)} unit="pax" />
            <Row label="Full Table Kit (tovaglia+candel+menù)" price="3/pax" on={pv.fullTable.on} setOn={v=>set("pv.fullTable.on",v)} qty={pv.fullTable.q} setQty={v=>set("pv.fullTable.q",v)} unit="pax" />
            <Row label="Semicerchio da terra" on={pv.semicerchio.on} setOn={v=>set("pv.semicerchio.on",v)} />
            <Row label="Altalena" on={pv.altalena.on} setOn={v=>set("pv.altalena.on",v)} extra={pv.altalena.e} setExtra={v=>set("pv.altalena.e",v)} />
            <Row label="Cerchio grande con palloncini" on={pv.cerchioG.on} setOn={v=>set("pv.cerchioG.on",v)} extra={pv.cerchioG.e} setExtra={v=>set("pv.cerchioG.e",v)} />
            <Row label="Cerchio piccolo con iniziali" on={pv.cerchioP.on} setOn={v=>set("pv.cerchioP.on",v)} extra={pv.cerchioP.e} setExtra={v=>set("pv.cerchioP.e",v)} />
            <Row label="SIAE, DJ, Console e Luci" price={P.siaeDj} on={pv.siaeDj.on} setOn={v=>set("pv.siaeDj.on",v)} />
            <Row label="SIAE" price={P.siae} on={pv.siae.on} setOn={v=>set("pv.siae.on",v)} />
            <Row label="Speaker" price={P.speaker} on={pv.speaker.on} setOn={v=>set("pv.speaker.on",v)} />
            <Row label="Fotografo" price={P.fotografo} on={pv.fotografo.on} setOn={v=>set("pv.fotografo.on",v)} />
            <Row label="Animazione" on={pv.animazione.on} setOn={v=>set("pv.animazione.on",v)} extra={pv.animazione.e} setExtra={v=>set("pv.animazione.e",v)} />
            <Row label="Strumento" on={pv.strumento.on} setOn={v=>set("pv.strumento.on",v)} extra={pv.strumento.e} setExtra={v=>set("pv.strumento.e",v)} />
            <Row label="Instax (100pz)" price={P.instax} on={pv.instax.on} setOn={v=>set("pv.instax.on",v)} />
            <Row label="Telo e Proiettore" price={P.telo} on={pv.telo.on} setOn={v=>set("pv.telo.on",v)} />
            <Row label="Fuochi D'artificio (Previa Autorizz. VV.FF.)" price={P.fuochi} on={pv.fuochi.on} setOn={v=>set("pv.fuochi.on",v)} />
            <Row label="Fontane pirotecniche" price={P.fontane} on={pv.fontane.on} setOn={v=>set("pv.fontane.on",v)} />
          </Box>
        </div>

        <div>
          <Box title="Menù" sx={{marginBottom:10}}>
            {[["smart","SMART"],["comfort","COMFORT"],["sharing","SHARING"],["bimbi","BAMBINI"]].map(([k,l])=>(
              <div key={k} style={{padding:"7px 0",borderBottom:`1px solid ${T.light}`}}>
                <div style={{fontSize:11,fontWeight:"800",color:T.teal,marginBottom:4}}>menù {l}</div>
                <div style={{display:"flex",gap:5,alignItems:"center",flexWrap:"wrap"}}>
                  <I value={mp[k].pax} onChange={v=>set("mp."+k+".pax",v)} placeholder="pax" w={55} type="number" />
                  <span style={{fontSize:10,color:T.sub}}>× pax ×</span>
                  <I value={mp[k].ep} onChange={v=>set("mp."+k+".ep",v)} placeholder="€/pax" w={60} type="number" />
                  <span style={{fontSize:10,color:T.sub}}>=</span>
                  <span style={{fontSize:12,fontWeight:"700",color:T.teal,minWidth:65,textAlign:"right"}}>
                    {((Number(mp[k].pax)||0)*(Number(mp[k].ep)||0)).toFixed(2)} €
                  </span>
                </div>
              </div>
            ))}
            <div style={{paddingTop:7}}>
              <span style={{fontSize:11,fontWeight:"700",color:T.sub}}>EXTRA</span>
              <I value={mp.extra} onChange={v=>set("mp.extra",v)} placeholder="€ extra" w="100%" sx={{display:"block",marginTop:4}} />
            </div>
          </Box>

          <div style={{background:T.teal,borderRadius:9,padding:14,marginBottom:10}}>
            {[["Drink & Aperitivo + Torta + Allestimento",calc.sub],["Totale menù",calc.menuTot],["Extra",calc.extra]].map(([l,v])=>v>0&&(
              <div key={l} style={{display:"flex",justifyContent:"space-between",marginBottom:5}}>
                <span style={{color:"rgba(255,255,255,0.7)",fontSize:11}}>{l}</span>
                <span style={{color:T.white,fontWeight:"600",fontSize:11}}>{v.toFixed(2)} €</span>
              </div>
            ))}
            <div style={{borderTop:"1px solid rgba(255,255,255,0.3)",paddingTop:8,marginTop:6,
              display:"flex",justifyContent:"space-between",alignItems:"center"}}>
              <span style={{color:T.white,fontSize:14,fontWeight:"700"}}>TOTALE PREVENTIVO</span>
              <span style={{color:T.white,fontSize:20,fontWeight:"900"}}>{calc.tot.toFixed(2)} €</span>
            </div>
          </div>

          <Box title="Sconto" sx={{marginBottom:10}}>
            <div style={{display:"flex",alignItems:"center",gap:8}}>
              <I value={d.sconto} onChange={v=>set("sconto",v)} w={60} type="number" />
              <span style={{fontSize:14,fontWeight:"700",color:T.teal}}>%</span>
              {Number(d.sconto)>0 && <span style={{fontSize:12,color:T.sub}}>= -{calc.sc.toFixed(2)} €</span>}
            </div>
            {Number(d.sconto)>0 && (
              <div style={{background:T.light,borderRadius:7,padding:"8px 12px",marginTop:7,
                display:"flex",justifyContent:"space-between",alignItems:"center"}}>
                <span style={{fontSize:13,fontWeight:"700",color:T.teal}}>TOTALE SCONTATO</span>
                <span style={{fontSize:18,fontWeight:"900",color:T.teal}}>{calc.totSc.toFixed(2)} €</span>
              </div>
            )}
          </Box>

          <Box title="Acconto (min 30%)" sx={{marginBottom:10}}>
            {(()=>{
              const base = Number(d.sconto)>0 ? calc.totSc : calc.tot;
              const sug = base > 0 ? (base * 0.30).toFixed(2) : null;
              return sug ? (
                <div style={{display:"flex",alignItems:"center",gap:8,marginBottom:8,
                  background:T.smartBg,borderRadius:7,padding:"7px 12px",border:`1px solid ${T.border}`}}>
                  <span style={{fontSize:11.5,color:T.sub}}>Suggerimento 30%:</span>
                  <span style={{fontSize:16,fontWeight:"900",color:T.teal}}>{sug} €</span>
                  <button onClick={()=>set("accontoI", sug)}
                    style={{marginLeft:"auto",background:T.teal,color:T.white,border:"none",
                      borderRadius:5,padding:"3px 10px",cursor:"pointer",fontSize:11,fontWeight:"700"}}>
                    Usa
                  </button>
                </div>
              ) : null;
            })()}
            <div style={{display:"flex",gap:8,alignItems:"center",marginBottom:7,flexWrap:"wrap"}}>
              <I value={d.accontoI} onChange={v=>set("accontoI",v)} placeholder="importo €" w={85} type="number" />
              {[["contanti","Contanti"],["pos","POS"]].map(([k,l])=>(
                <label key={k} style={{display:"flex",alignItems:"center",gap:4,cursor:"pointer"}}>
                  <input type="radio" name="acc" value={k} checked={d.accontoM===k}
                    onChange={()=>set("accontoM",k)} style={{accentColor:T.teal}} />
                  <span style={{fontSize:12}}>{l}</span>
                </label>
              ))}
            </div>
            <div style={{fontSize:11,fontWeight:"700",color:T.sub,marginBottom:5}}>Pagolight (a rate)</div>
            <div style={{display:"flex",gap:6}}>
              {["r1","r2","r3"].map((k,i)=>(
                <div key={k}>
                  <div style={{fontSize:10,color:T.sub,marginBottom:2}}>Rata {i+1}</div>
                  <I value={d.pagolight[k]} onChange={v=>set("pagolight."+k,v)} placeholder="€" w={65} type="number" />
                </div>
              ))}
            </div>
            <div style={{marginTop:9}}>
              <Cb checked={d.fattura} onChange={v=>set("fattura",v)} label="Fattura (compilare modulo)" />
            </div>
          </Box>

          <Box title="Note preventivo">
            <textarea value={d.notePrev} onChange={e=>set("notePrev",e.target.value)} placeholder="Note…"
              style={{width:"100%",boxSizing:"border-box",border:`1px solid ${T.border}`,borderRadius:5,
                padding:6,fontSize:12,resize:"vertical",minHeight:60,fontFamily:"inherit",outline:"none"}} />
          </Box>

          <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:8,marginTop:10}}>
            <div>
              <div style={{fontSize:10,color:T.sub,marginBottom:3}}>Data Preventivo</div>
              <I value={d.dataDoc} onChange={v=>set("dataDoc",v)} type="date" w="100%" />
            </div>
            <div>
              <div style={{fontSize:10,color:T.sub,marginBottom:3}}>Firma Cliente</div>
              <I value={d.firmaC} onChange={v=>set("firmaC",v)} placeholder="firma…" w="100%" />
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

// ─── MENU TEMPLATE ────────────────────────────────────────────────────────────
const MenuShell = ({title,pref,menu,set,sections,rightSections,extraRight}) => (
  <div>
    <div style={{display:"flex",gap:8,alignItems:"center",marginBottom:10}}>
      <span style={{fontSize:15,fontWeight:"800",color:T.teal}}>{title}</span>
      <div style={{display:"flex",gap:6,alignItems:"center",marginLeft:"auto",flexWrap:"wrap"}}>
        <span style={{fontSize:11,color:T.sub}}>Pax Conf.</span>
        <I value={menu.nPaxConf} onChange={v=>set(pref+".nPaxConf",v)} w={55} type="number" />
        {menu.nPort!==undefined && <>
          <span style={{fontSize:11,color:T.sub}}>Port.</span>
          <I value={menu.nPort} onChange={v=>set(pref+".nPort",v)} w={45} type="number" />
        </>}
      </div>
    </div>
    <div style={{display:"grid",gridTemplateColumns:`repeat(${rightSections?2:sections.length>8?2:1},1fr)`,gap:12}}>
      <div>{sections.map(([k,title])=><Sec key={k} title={title} data={menu[k]||{}} pref={pref+"."+k} set={set} />)}</div>
      {rightSections && <div>{rightSections.map(([k,title])=><Sec key={k} title={title} data={menu[k]||{}} pref={pref+"."+k} set={set} />)}{extraRight}</div>}
    </div>
    <AllergBlock menu={menu} pref={pref} set={set} />
  </div>
);

// ─── TAB 4: SMART ─────────────────────────────────────────────────────────────
const TabSmart = ({d,set}) => (
  <MenuShell title="Menù SMART" pref="ms" menu={d.ms} set={set}
    sections={[["tapas","TAPAS"],["farciti","FARCITI"],["primi","PRIMI"],["secondi","SECONDI"]]}
    rightSections={[["poke","POKÉ"],["spiedini","SPIEDINI"],["dtrad","MINI DESSERT TRADIZIONALI"],["dmod","MINI DESSERT MODERNI"],["frutta","FRUTTA"],["vB","VINI BIANCHI"],["vR","VINI ROSSI"],["vRos","ROSATI"],["boll","BOLLICINE"],["bollD","BOLLICINE DESSERT"]]}
  />
);

