// ─── DEEP MERGE ───────────────────────────────────────────────────────────────
function deepMerge(base, patch) {
  if (!patch || typeof patch !== "object") return base;
  const result = {...base};
  for (const key of Object.keys(patch)) {
    if (patch[key] === null || patch[key] === undefined || patch[key] === "") continue;
    if (typeof patch[key] === "object" && !Array.isArray(patch[key]) && typeof base[key] === "object" && !Array.isArray(base[key])) {
      result[key] = deepMerge(base[key], patch[key]);
    } else {
      result[key] = patch[key];
    }
  }
  return result;
}

